changeSet.sql:
-- Individual Password Reset Audit table CREATE TABLE IF NOT EXISTS public.individual_password_reset_audit ( id UUID NOT NULL, individual_id UUID NOT NULL, email VARCHAR(200) NOT NULL, reset_link VARCHAR(200) NULL, reset_link_requested_at TIMESTAMP NULL, reset_link_expires_at TIMESTAMP NULL, reset_completed_at TIMESTAMP NULL, reset_status VARCHAR(50) NULL, is_active BOOLEAN NULL, created_by UUID NULL, updated_by UUID NULL, CONSTRAINT individual_password_reset_audit_pkey PRIMARY KEY (id), CONSTRAINT individual_password_reset_audit_individual_id_fkey FOREIGN KEY (individual_id) REFERENCES public.individual(id) );
-- Individual Verification Audit table CREATE TABLE IF NOT EXISTS public.individual_verification_audit ( id UUID NOT NULL, contact_type VARCHAR(50) NOT NULL, contact_value VARCHAR(255) NOT NULL, activation_link BOOLEAN DEFAULT false, activation_link_created_at TIMESTAMP NULL, activation_link_expires_at TIMESTAMP NULL, activation_link_verified_at TIMESTAMP NULL, ip_address VARCHAR(40) NULL, role VARCHAR(40) NULL, verification_status VARCHAR(50) NULL, is_active BOOLEAN NULL, created_by UUID NULL, updated_by UUID NULL, created_on TIMESTAMP NULL, updated_on TIMESTAMP NULL, otp VARCHAR(10) NULL, meta_data JSONB NULL, org_id UUID NULL, CONSTRAINT individual_verification_audit_pkey PRIMARY KEY (id) );
-- Individual Sessions table CREATE TABLE IF NOT EXISTS public.individual_sessions ( id UUID NOT NULL, individual_id UUID NOT NULL, accesstoken VARCHAR NOT NULL, accesstoken_expirytime TIMESTAMP NOT NULL, accesstoken_generated_on TIMESTAMP NOT NULL, refreshtoken VARCHAR NOT NULL, refreshtoken_expirytime TIMESTAMP NOT NULL, refreshtoken_generated_on TIMESTAMP NOT NULL, ipaddress VARCHAR NULL, CONSTRAINT individual_sessions_pkey PRIMARY KEY (id), CONSTRAINT individual_sessions_ind_fk FOREIGN KEY (individual_id) REFERENCES public.individual(id) );
